mapper.select:
SELECT c.id AS categoryId, c.name AS categoryName, c.icon AS categoryIcon, c.color AS categoryColor, COALESCE(SUM(t.amount), 0) AS totalAmount, COUNT(t.id) AS count FROM category c LEFT JOIN `transaction` t ON t.category_id = c.id AND t.deleted = 0 AND t.user_id = #{userId} AND t.type = #{type}
AND t.date >= #{startDate}
AND t.date <= #{endDate}
WHERE c.deleted = 0 GROUP BY c.id, c.name, c.icon, c.color ORDER BY totalAmount DESC

SELECT COALESCE(SUM(amount), 0)
FROM `transaction`
WHERE deleted = 0
  AND user_id = #{userId}
  AND type = #{type}

    AND date >= #{startDate}


    AND date <= #{endDate}
